    <div className="space-y-10 animate-in fade-in duration-700 pb-20">
      {/* Header Stat & Insight AI */}
      <div className="flex flex-col xl:flex-row gap-6">
        <div className="flex-1 bg-white px-10 py-8 rounded-[3.5rem] border border-slate-100 shadow-sm flex items-center justify-between">
          <div className="flex items-center gap-6">
             <div className="w-16 h-16 bg-indigo-50 text-indigo-600 rounded-3xl flex items-center justify-center shadow-inner">
