                </p>
                <h2 className="text-xl font-black text-slate-900 tracking-tight leading-tight">"{aiInsight}"</h2>
             </div>
          </div>
          <button onClick={() => setAiChatOpen(true)} className="px-6 py-3 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-slate-900 transition-all shadow-xl shadow-indigo-600/20 active:scale-95">Consultar IA</button>
        </div>

        <div className="bg-slate-900 px-10 py-8 rounded-[3.5rem] text-white flex items-center gap-8 shadow-2xl relative overflow-hidden">
           <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-500/10 rounded-full blur-2xl"></div>
           <div className="flex items-center gap-4 relative z-10">
              <div className="w-3 h-3 bg-emerald-500 rounded-full animate-pulse shadow-[0_0_15px_rgba(16,185,129,0.8)]"></div>
              <div>
                 <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Sincronização Cloud</p>
                 <p className="text-sm font-bold">100% Ativa</p>
              </div>
           </div>
           <div className="w-px h-10 bg-white/10 hidden md:block"></div>
           <div className="hidden md:flex flex-col items-end relative z-10">
              <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Data do Sistema</p>
              <p className="text-sm font-bold">{new Date().toLocaleDateString('pt-MZ')}</p>
           </div>
        </div>
      </div>

      {/* KPI Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {[
