          { label: 'Equipa Monte', value: stats.employees, icon: <Users className="text-emerald-600" />, trend: 'Colaboradores Ativos', color: 'emerald' },
          { label: 'Portfólio', value: stats.properties, icon: <Home className="text-blue-600" />, trend: 'Imóveis Registados', color: 'blue' },
          { label: 'Inbox', value: stats.contacts, icon: <MessageSquare className="text-rose-600" />, trend: 'Novas Mensagens', color: 'rose' },
        ].map((kpi, idx) => (
          <div key={idx} className="bg-white p-10 rounded-[3.5rem] border border-slate-100 shadow-sm hover:shadow-2xl transition-all group overflow-hidden relative">
            <div className="absolute top-0 right-0 w-32 h-32 bg-slate-50 rounded-full translate-x-12 -translate-y-12 group-hover:scale-125 transition-transform duration-700"></div>
            <div className="relative z-10">
              <div className="flex items-center gap-4 mb-6">
                <div className="p-4 bg-slate-50 rounded-[1.5rem] text-slate-600 group-hover:bg-white group-hover:shadow-md transition-all">{kpi.icon}</div>
                <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{kpi.label}</span>
              </div>
