const DashboardView: React.FC = () => {
  const [stats, setStats] = useState({ 
    revenue: 0, 
    expenses: 0, 
    employees: 0, 
    properties: 0, 
    contacts: 0,
    pendingApps: 0 
  });
  const [recentMessages, setRecentMessages] = useState<any[]>([]);
  const [recentApps, setRecentApps] = useState<JobApplication[]>([]);
  const [loading, setLoading] = useState(true);
  const [dbError, setDbError] = useState<string | null>(null);
  const [aiInsight, setAiInsight] = useState<string>('Analizando pulso da Monte Imobiliária...');

  // AI Chat States
  const [aiChatOpen, setAiChatOpen] = useState(false);
  const [chatInput, setChatInput] = useState('');
  const [chatMessages, setChatMessages] = useState<{role: 'user' | 'ai', text: string}[]>([
    { role: 'ai', text: 'Olá! Sou o Monte AI. Como posso ajudar com a gestão estratégica da Monte Imobiliária hoje?' }
  ]);
  const [isAiTyping, setIsAiTyping] = useState(false);

  useEffect(() => {
    fetchGlobalStats();
  }, []);

  async function fetchGlobalStats() {
    setLoading(true);
    try {
      const [txRes, empRes, propRes, contactRes, msgListRes, appListRes, appCountRes] = await Promise.all([
        supabase.from('transactions').select('*'),
        supabase.from('employees').select('*', { count: 'exact', head: true }),
        supabase.from('properties').select('*', { count: 'exact', head: true }),
        supabase.from('contact_requests').select('*', { count: 'exact', head: true }),
        supabase.from('contact_requests').select('*').order('created_at', { ascending: false }).limit(3),
        supabase.from('job_applications').select('*').order('created_at', { ascending: false }).limit(4),
        supabase.from('job_applications').select('*', { count: 'exact', head: true }).eq('status', 'Pendente')
      ]);

      const txs = txRes.data || [];
      const rev = txs.filter(t => t.type === 'RECEITA').reduce((a, b) => a + Number(b.amount || 0), 0);
      const exp = txs.filter(t => t.type === 'DESPESA').reduce((a, b) => a + Number(b.amount || 0), 0);

      const newStats = {
        revenue: rev, 
        expenses: exp,
        employees: empRes.count || 0,
        properties: propRes.count || 0, 
        contacts: contactRes.count || 0,
        pendingApps: appCountRes.count || 0
      };
      setStats(newStats);
      setRecentMessages(msgListRes.data || []);
      setRecentApps(appListRes.data || []);

      const insight = await getStrategicInsight(`Fluxo: ${rev-exp}MT, Imóveis: ${propRes.count}, Staff: ${empRes.count}`);
      setAiInsight(insight);
    } catch (error: any) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  }

  const handleSendToAI = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!chatInput.trim() || isAiTyping) return;

    const userMsg = chatInput;
    setChatMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setChatInput('');
    setIsAiTyping(true);

    const response = await chatWithMonteAI(userMsg, stats);
    setChatMessages(prev => [...prev, { role: 'ai', text: response }]);
    setIsAiTyping(false);
  };

  const chartData = useMemo(() => [
    { name: 'Receitas', value: stats.revenue, color: '#6366f1' },
    { name: 'Despesas', value: stats.expenses, color: '#f43f5e' }
  ], [stats]);

  if (loading) return (
    <div className="h-full flex flex-col items-center justify-center py-32 gap-6 bg-slate-50">
      <div className="w-16 h-16 bg-indigo-600 rounded-[2rem] flex items-center justify-center p-4 shadow-2xl animate-bounce">
         <img src="https://i.ibb.co/LzfNdf7Y/building-logo.png" className="w-full h-full object-contain brightness-0 invert" alt="Monte Logo" />
      </div>
      <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.4em] animate-pulse">Sincronizando Monte Imobiliária...</p>
    </div>
