import React, { useState, useEffect, useRef } from 'react';
import { MOCK_PROPERTIES } from '../constants';
import { 
  MapPin, BedDouble, Bath, Ruler, ArrowLeft, Share2, Heart, 
  ShieldCheck, ChevronRight, ChevronLeft, MessageSquare, Phone, Mail, 
  Maximize2, Send, Loader2, User, Bot, Sparkles, ZoomIn
} from 'lucide-react';
import { supabase } from '../supabaseClient';

interface Message {
  id: string;
  text: string;
  sender: 'user' | 'agent';
  timestamp: Date;
}

interface PropertyDetailViewProps {
  propertyId: string | null;
  onBack: () => void;
}

const PropertyDetailView: React.FC<PropertyDetailViewProps> = ({ propertyId, onBack }) => {
  const [isLoading, setIsLoading] = useState(true);
  const property = MOCK_PROPERTIES.find(p => p.id === propertyId);

  const images = property ? [property.image, ...property.gallery] : [];
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isTransitioning, setIsTransitioning] = useState(false);
  const thumbnailRefs = useRef<(HTMLButtonElement | null)[]>([]);
  const scrollContainerRef = useRef<HTMLDivElement>(null);

  // Chat States
  const [messages, setMessages] = useState<Message[]>([
    { id: '1', text: 'Olá! Como posso ajudar com este imóvel?', sender: 'agent', timestamp: new Date() }
  ]);
  const [inputText, setInputText] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isSending, setIsSending] = useState(false);
  const chatEndRef = useRef<HTMLDivElement>(null);

  // Simulação de busca de dados
  useEffect(() => {
    setIsLoading(true);
    const timer = setTimeout(() => {
      setIsLoading(false);
    }, 1200);
    return () => clearTimeout(timer);
  }, [propertyId]);

  // Navegação via Teclado
  useEffect(() => {
    if (isLoading) return;
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'ArrowRight') nextImage();
      if (e.key === 'ArrowLeft') prevImage();
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [currentIndex, isLoading]);

  // Scroll automático para miniatura ativa
  useEffect(() => {
    if (!isLoading && thumbnailRefs.current[currentIndex] && scrollContainerRef.current) {
      thumbnailRefs.current[currentIndex]?.scrollIntoView({
        behavior: 'smooth',
        block: 'nearest',
        inline: 'center'
      });
    }
  }, [currentIndex, isLoading]);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isTyping]);

  if (!property && !isLoading) return (
    <div className="py-20 text-center">
      <p>Imóvel não encontrado.</p>
      <button onClick={onBack} className="text-blue-600 font-bold mt-4">Voltar</button>
    </div>
  );

  const nextImage = () => {
    triggerTransition();
    setCurrentIndex((prev) => (prev + 1) % images.length);
  };

  const prevImage = () => {
    triggerTransition();
    setCurrentIndex((prev) => (prev - 1 + images.length) % images.length);
  };

  const triggerTransition = () => {
    setIsTransitioning(true);
    setTimeout(() => setIsTransitioning(false), 300);
  };

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputText.trim()) return;

    const userMsg: Message = {
      id: Date.now().toString(),
      text: inputText,
      sender: 'user',
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMsg]);
    setInputText('');
    setIsSending(true);

    try {
      await supabase.from('contact_requests').insert([{
        name: 'Interessado (Chat)',
        email: 'chat@web.user',
        subject: `Dúvida Imóvel: ${property?.title}`,
        message: inputText,
        created_at: new Date().toISOString()
      }]);

      setIsTyping(true);
      setTimeout(() => {
        const agentMsg: Message = {
          id: (Date.now() + 1).toString(),
          text: 'Recebemos a sua mensagem! Um dos nossos consultores irá analisar o seu pedido e responder via WhatsApp ou Email brevemente. Posso ajudar com mais alguma coisa?',
          sender: 'agent',
          timestamp: new Date()
        };
        setMessages(prev => [...prev, agentMsg]);
        setIsTyping(false);
      }, 1500);

    } catch (err) {
      console.error("Chat error:", err);
    } finally {
      setIsSending(false);
    }
  };

  const LoadingSkeleton = () => (
    <div className="lg:col-span-2 space-y-10 animate-pulse">
      {/* Gallery Skeleton */}
      <div className="space-y-6">
        <div className="aspect-video rounded-[2.5rem] bg-slate-200"></div>
        <div className="flex gap-4 overflow-hidden">
          {[1, 2, 3, 4].map(i => (
            <div key={i} className="shrink-0 w-36 aspect-[4/3] rounded-2xl bg-slate-200"></div>
          ))}
        </div>
      </div>
      {/* Info Skeleton */}
      <div className="bg-white p-8 md:p-12 rounded-[2.5rem] border border-slate-100 shadow-sm space-y-8">
        <div className="flex justify-between items-start">
          <div className="space-y-3 w-1/2">
            <div className="h-10 bg-slate-200 rounded-xl w-full"></div>
            <div className="h-6 bg-slate-100 rounded-lg w-2/3"></div>
          </div>
          <div className="space-y-3 w-1/4">
            <div className="h-4 bg-slate-100 rounded-lg w-full"></div>
            <div className="h-12 bg-slate-200 rounded-xl w-full"></div>
          </div>
        </div>
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 py-10 border-y border-slate-50">
          {[1, 2, 3, 4].map(i => (
            <div key={i} className="h-24 bg-slate-50 rounded-[2rem]"></div>
          ))}
        </div>
        <div className="space-y-4">
          <div className="h-8 bg-slate-200 rounded-lg w-1/3"></div>
          <div className="h-4 bg-slate-100 rounded-lg w-full"></div>
          <div className="h-4 bg-slate-100 rounded-lg w-full"></div>
          <div className="h-4 bg-slate-100 rounded-lg w-3/4"></div>
        </div>
      </div>
    </div>
  );

  return (
    <div className="max-w-7xl mx-auto py-12 px-4 md:px-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      {/* Breadcrumbs & Actions */}
      <div className="flex items-center justify-between mb-8">
        <button onClick={onBack} className="flex items-center gap-2 text-slate-500 hover:text-blue-600 font-bold text-sm transition-all group">
          <ArrowLeft size={18} className="group-hover:-translate-x-1 transition-transform" /> Voltar ao Catálogo
        </button>
        <div className="flex gap-2">
           <button className="p-2.5 bg-white border border-slate-200 rounded-xl text-slate-500 hover:text-blue-600 transition-all" title="Partilhar"><Share2 size={18} /></button>
           <button className="p-2.5 bg-white border border-slate-200 rounded-xl text-slate-500 hover:text-red-500 transition-all" title="Favoritos"><Heart size={18} /></button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-12">
        {isLoading ? (
          <LoadingSkeleton />
        ) : property && (
          /* Main Content (Images & Info) */
          <div className="lg:col-span-2 space-y-10">
            {/* Gallery Section */}
            <div className="space-y-6">
              <div className="relative group aspect-video rounded-[2.5rem] overflow-hidden shadow-2xl bg-slate-100">
                <img 
                  src={images[currentIndex]} 
                  alt={`${property.title} - Imagem ${currentIndex + 1}`} 
                  className={`w-full h-full object-cover transition-all duration-500 transform ${isTransitioning ? 'opacity-0 scale-105' : 'opacity-100 scale-100'}`}
                />

                <div className="absolute inset-0 flex items-center justify-between px-6 opacity-0 group-hover:opacity-100 transition-opacity z-20">
                  <button 
                    onClick={prevImage}
                    className="p-4 bg-white/90 backdrop-blur-md text-slate-900 rounded-full shadow-lg hover:bg-blue-600 hover:text-white transition-all transform hover:scale-110 active:scale-90"
                  >
                    <ChevronLeft size={28} />
                  </button>
                  <button 
                    onClick={nextImage}
                    className="p-4 bg-white/90 backdrop-blur-md text-slate-900 rounded-full shadow-lg hover:bg-blue-600 hover:text-white transition-all transform hover:scale-110 active:scale-90"
                  >
                    <ChevronRight size={28} />
                  </button>
                </div>

                <div className="absolute top-6 left-6 flex gap-3 z-20">
                  <div className="bg-blue-600 text-white px-5 py-2 rounded-full font-black text-xs uppercase tracking-widest shadow-lg flex items-center gap-2">
                     <ShieldCheck size={14} /> {property.dealType}
                  </div>
                  <div className="bg-white/90 backdrop-blur-md text-slate-900 px-5 py-2 rounded-full font-black text-xs uppercase tracking-widest shadow-lg flex items-center gap-2">
                    <Maximize2 size={14} /> {currentIndex + 1} / {images.length}
                  </div>
                </div>

                <div className="absolute bottom-6 right-6 z-20">
                  <button className="p-4 bg-white/20 backdrop-blur-lg hover:bg-white/40 text-white rounded-2xl transition-all border border-white/30 group/btn">
                    <ZoomIn size={24} className="group-hover/btn:scale-125 transition-transform" />
                  </button>
                </div>
              </div>

              {/* Thumbnail Carousel */}
              <div 
                ref={scrollContainerRef}
                className="flex gap-4 overflow-x-auto pb-4 scrollbar-hide px-1"
              >
                {images.map((img, i) => (
                  <button 
                    key={i} 
                    // Fix: Ensure ref callback returns void by wrapping assignment in braces
                    ref={el => { thumbnailRefs.current[i] = el; }}
                    onClick={() => {
                      triggerTransition();
                      setCurrentIndex(i);
                    }}
                    className={`relative shrink-0 w-36 aspect-[4/3] rounded-2xl overflow-hidden border-4 transition-all duration-300 ${
                      currentIndex === i 
                      ? 'border-blue-600 ring-4 ring-blue-100 scale-95 opacity-100 shadow-xl' 
                      : 'border-transparent opacity-60 hover:opacity-100 grayscale hover:grayscale-0'
                    }`}
                  >
                    <img src={img} className="w-full h-full object-cover" alt={`Miniatura ${i + 1}`} />
                    {currentIndex === i && (
                      <div className="absolute inset-0 bg-blue-600/10 flex items-center justify-center">
                        <div className="w-2 h-2 bg-blue-600 rounded-full animate-ping"></div>
                      </div>
                    )}
                  </button>
                ))}
              </div>
            </div>

            <div className="bg-white p-8 md:p-12 rounded-[2.5rem] border border-slate-100 shadow-sm">
               <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-10">
                  <div>
                    <h1 className="text-4xl font-black text-slate-900 mb-3 tracking-tight">{property.title}</h1>
                    <p className="flex items-center gap-2 text-slate-500 font-medium text-lg">
                      <MapPin size={22} className="text-blue-600" /> {property.location}, Moçambique
                    </p>
                  </div>
                  <div className="text-right">
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Valor de {property.dealType === 'Venda' ? 'Venda' : 'Renda'}</p>
                    <p className="text-5xl font-black text-blue-600 tracking-tighter">
                      {property.price.toLocaleString('pt-MZ', { style: 'currency', currency: 'MZN', minimumFractionDigits: 0 })}
                    </p>
                  </div>
               </div>

               <div className="grid grid-cols-2 md:grid-cols-4 gap-4 py-10 border-y border-slate-50">
                  {[
                    { icon: <BedDouble size={28} />, label: 'Quartos', value: property.beds },
