import React, { useState } from 'react';
import { supabase } from '../supabaseClient';
import { Mail, Lock, LogIn, Loader2, AlertCircle, ArrowLeft, Info } from 'lucide-react';
import { UserRole } from '../types';

interface LoginViewProps {
  onLoginSuccess: (user: any) => void;
  onBack: () => void;
}

const LoginView: React.FC<LoginViewProps> = ({ onLoginSuccess, onBack }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [showDevMessage, setShowDevMessage] = useState(false);

  const handleSignIn = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);
    setShowDevMessage(false);

    try {
      const { data: authData, error: authError } = await supabase.auth.signInWithPassword({
        email, password,
      });
      if (authError) throw authError;

      const { data: empData } = await supabase
        .from('employees')
        .select('*')
        .eq('email', email)
        .single();

      const userData = {
        id: authData.user?.id,
        name: empData?.name || authData.user?.email?.split('@')[0],
        email: authData.user?.email,
        role: empData?.role || UserRole.EMPLOYEE,
        avatar: empData?.avatar || `https://picsum.photos/seed/${authData.user?.id}/100`,
      };

      onLoginSuccess(userData);
    } catch (err: any) {
      setError(err.message === 'Invalid login credentials' ? 'E-mail ou senha incorretos.' : err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-50 p-4 animate-in fade-in duration-500">
      <div className="bg-white rounded-[4rem] shadow-2xl p-10 md:p-16 max-w-md w-full border border-slate-100 relative overflow-hidden">
        <div className="absolute top-0 right-0 w-32 h-32 bg-blue-600/5 rounded-full -translate-y-1/2 translate-x-1/2 blur-2xl"></div>

        <div className="text-center mb-10">
          <div className="w-24 h-24 bg-blue-600 rounded-[2.5rem] flex items-center justify-center mx-auto mb-8 shadow-2xl shadow-blue-500/30 p-4">
            <img src="https://i.ibb.co/LzfNdf7Y/building-logo.png" alt="Monte Logo" className="w-full h-full object-contain brightness-0 invert" />
          </div>
          <h2 className="text-3xl font-black text-slate-900 tracking-tight uppercase">MONTE IMOBILIÁRIA</h2>
          <p className="text-slate-500 font-bold text-[10px] uppercase tracking-widest mt-2 px-4 py-1 bg-slate-50 rounded-full inline-block">Sincronização Cloud Ativa</p>
        </div>

        {error && (
          <div className="mb-6 bg-red-50 border-l-4 border-red-500 p-4 rounded-xl flex items-center gap-3 text-red-700 text-xs font-bold animate-shake">
            <AlertCircle size={18} /> {error}
          </div>
        )}

        <form onSubmit={handleSignIn} className="space-y-6">
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">E-mail Staff</label>
            <div className="relative">
              <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                required type="email" value={email} onChange={(e) => setEmail(e.target.value)}
                className="w-full pl-12 pr-4 py-5 bg-slate-50 rounded-[1.5rem] border-none focus:ring-2 focus:ring-blue-600 font-bold text-sm"
                placeholder="nome@monte-imobiliaria.com"
              />
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Chave de Segurança</label>
            <div className="relative">
              <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                required type="password" value={password} onChange={(e) => setPassword(e.target.value)}
                className="w-full pl-12 pr-4 py-5 bg-slate-50 rounded-[1.5rem] border-none focus:ring-2 focus:ring-blue-600 font-bold text-sm"
                placeholder="••••••••"
              />
            </div>
          </div>

          <div className="space-y-4">
            <button 
              disabled={loading} type="submit" 
              className={`w-full py-6 bg-blue-600 text-white rounded-[2rem] font-black text-xs uppercase tracking-widest flex items-center justify-center gap-3 hover:bg-blue-700 transition-all shadow-xl shadow-blue-500/20 active:scale-95 ${loading ? 'animate-pulse opacity-90 cursor-wait' : ''}`}
            >
              {loading ? <Loader2 className="animate-spin" size={20} /> : <><LogIn size={20} /> Aceder ao ERP</>}
            </button>

            <div className="text-center">
              <button 
                type="button"
                onClick={() => setShowDevMessage(true)}
                className="text-[10px] font-black text-slate-400 uppercase tracking-widest hover:text-blue-600 transition-colors"
              >
                Esqueci minha senha?
              </button>
            </div>
          </div>
        </form>

        {showDevMessage && (
          <div className="mt-6 p-4 bg-amber-50 border-l-4 border-amber-500 rounded-xl flex items-center gap-3 text-amber-700 text-[10px] font-black uppercase tracking-widest animate-in slide-in-from-top-2">
            <Info size={16} className="shrink-0" /> Funcionalidade em desenvolvimento
          </div>
        )}

        <div className="mt-10 text-center">
          <button onClick={onBack} className="text-slate-400 hover:text-blue-600 font-black text-[10px] uppercase tracking-widest flex items-center justify-center gap-2 mx-auto transition-colors">
            <ArrowLeft size={14} /> Voltar ao Portal Público
          </button>
        </div>
      </div>
    </div>
  );
};

export default LoginView;

import React, { useState, useEffect } from 'react';
import { Briefcase, MapPin, ArrowRight, UserPlus, Mail, Loader2, Info, ChevronDown, ChevronUp, Image as ImageIcon, X, Send, CheckCircle2, Globe, Link as LinkIcon, Phone, ShieldCheck, HelpCircle, AlertCircle } from 'lucide-react';
import { supabase } from '../supabaseClient';
import { JobVacancy } from '../types';

const CareerView: React.FC = () => {
  const [vacancies, setVacancies] = useState<JobVacancy[]>([]);
  const [loading, setLoading] = useState(true);
  const [expandedId, setExpandedId] = useState<string | null>(null);

  const [showApplyModal, setShowApplyModal] = useState(false);
  const [selectedJob, setSelectedJob] = useState<JobVacancy | null>(null);
  const [isApplying, setIsApplying] = useState(false);
  const [applyStatus, setApplyStatus] = useState<'idle' | 'success' | 'error'>('idle');
  const [hasConsent, setHasConsent] = useState(false);
  const [applyForm, setApplyForm] = useState({ name: '', email: '', phone: '', linkedin: '', message: '' });

  useEffect(() => {
    fetchVacancies();
  }, []);

  async function fetchVacancies() {
    setLoading(true);
    try {
      const { data, error } = await supabase
        .from('job_vacancies')
        .select('*')
        .eq('status', 'Open')
        .order('created_at', { ascending: false });
      if (!error) setVacancies(data || []);
    } catch (err) {
      console.error("Error fetching jobs:", err);
    } finally {
      setLoading(false);
    }
  }

  const handleOpenApply = (job: JobVacancy) => {
    setSelectedJob(job);
    setApplyStatus('idle');
    setHasConsent(false);
    setApplyForm({ name: '', email: '', phone: '', linkedin: '', message: '' });
    setShowApplyModal(true);
  };

  const handleApplySubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!hasConsent) return;
    setIsApplying(true);
    setApplyStatus('idle');

    try {
      const now = new Date().toISOString();
      const { error } = await supabase.from('job_applications').insert([{
        job_id: selectedJob?.id, 
        job_title: selectedJob?.title, 
        applicant_name: applyForm.name.trim(),
        applicant_email: applyForm.email.trim(), 
        applicant_phone: applyForm.phone.trim(), 
        applicant_linkedin: applyForm.linkedin.trim(),
        message: applyForm.message.trim(), 
        status: 'Pendente', 
        consent_given: true,
        consent_timestamp: now,
        created_at: now
      }]);
      if (error) throw error;
      setApplyStatus('success');
    } catch (err) {
      console.error("Erro na candidatura:", err);
      setApplyStatus('error');
    } finally {
      setIsApplying(false);
    }
  };

  if (loading) return (
    <div className="py-32 flex flex-col items-center gap-4 bg-white min-h-[60vh]">
       <Loader2 className="animate-spin text-blue-600" size={48} />
       <p className="text-[11px] font-black text-slate-400 uppercase tracking-widest animate-pulse">Sincronizando com a Monte Imobiliária...</p>
    </div>
  );

  return (
    <div className="animate-in fade-in duration-700" role="main">
      <section className="relative h-[450px] flex items-center justify-center text-center text-white overflow-hidden">
        <div className="absolute inset-0 z-0">
          <img src="https://images.unsplash.com/photo-1522071820081-009f0129c71c?auto=format&fit=crop&q=80&w=1200" alt="Team" className="w-full h-full object-cover" />
          <div className="absolute inset-0 bg-slate-900/75 backdrop-blur-[1px]"></div>
        </div>
        <div className="relative z-10 max-w-4xl px-4">
          <h1 className="text-4xl md:text-6xl font-black mb-6 leading-tight tracking-tighter">
            Trabalhe na <span className="text-blue-400">Monte Imobiliária</span>
          </h1>
          <p className="text-slate-300 text-lg md:text-xl font-medium max-w-2xl mx-auto mb-10 leading-relaxed italic">
            Canal Oficial: <span className="text-white font-bold">monteimobiliario@gmail.com</span> | <span className="text-white font-bold">+258 87 501 8283</span>
          </p>
          <a href="#vagas" className="bg-blue-600 hover:bg-blue-700 text-white px-12 py-5 rounded-[2.5rem] font-black text-xs uppercase tracking-widest transition-all shadow-2xl">Explorar Oportunidades</a>
        </div>
      </section>

      <section id="vagas" className="py-20 px-4 md:px-8 bg-slate-50">
        <div className="max-w-6xl mx-auto">
          <div className="flex items-center justify-between mb-12">
            <h2 className="text-3xl font-black text-slate-900 tracking-tight">Vagas em Destaque</h2>
            <div className="flex items-center gap-2 px-4 py-2 bg-white rounded-full border border-slate-200 text-[10px] font-black text-slate-400 uppercase tracking-widest">
               <ShieldCheck size={14} className="text-blue-600" /> Vagas Auditadas
            </div>
          </div>

          <div className="space-y-6">
            {vacancies.length === 0 ? (
              <div className="bg-white p-16 rounded-[3.5rem] border border-dashed border-slate-200 text-center">
                 <Briefcase size={40} className="mx-auto text-slate-200 mb-4" />
                 <p className="text-slate-400 font-bold uppercase text-[10px]">De momento não temos vagas abertas. Tente mais tarde.</p>
              </div>
            ) : vacancies.map((job) => (
              <div key={job.id} className="bg-white rounded-[3.5rem] border border-slate-100 shadow-sm overflow-hidden transition-all hover:shadow-2xl hover:scale-[1.005]">
                <div className="p-8 flex flex-col md:flex-row md:items-center justify-between gap-6 cursor-pointer" onClick={() => setExpandedId(expandedId === job.id ? null : job.id)}>
                   <div className="flex-1">
                      <h3 className="text-2xl font-black text-slate-900 mb-2">{job.title}</h3>
                      <div className="flex flex-wrap gap-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                         <span className="flex items-center gap-1.5"><MapPin size={12} className="text-blue-600" /> {job.location}</span>
                         <span className="flex items-center gap-1.5"><Briefcase size={12} className="text-blue-600" /> {job.area}</span>
                      </div>
                   </div>
                   <div className="flex items-center gap-4">
                      <button onClick={(e) => { e.stopPropagation(); handleOpenApply(job); }} className="px-8 py-4 bg-blue-600 text-white rounded-[2rem] font-black text-[10px] uppercase tracking-widest hover:bg-slate-900 transition-all">Candidatar-se</button>
                      <div className={`p-3 rounded-full bg-slate-50 text-slate-400 transition-transform ${expandedId === job.id ? 'rotate-180' : ''}`}><ChevronDown size={20} /></div>
