                </div>
                {expandedId === job.id && (
                  <div className="px-10 pb-12 pt-4 border-t border-slate-50 animate-in slide-in-from-top-4 duration-500">
                     <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
                        <div className="lg:col-span-8">
                           <div className="prose prose-slate max-w-none text-slate-600 font-medium whitespace-pre-line leading-relaxed text-sm bg-slate-50 p-10 rounded-[3.5rem] border border-slate-100">
                              {job.description || "Descrição em sincronização técnica."}
