                        </div>
                        <div className="lg:col-span-4 space-y-6">
                           <div className="p-8 bg-white border border-slate-100 rounded-[3.5rem] shadow-xl">
                              <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-6 border-b border-slate-50 pb-4">Suporte ao Candidato</h4>
                              <div className="space-y-4">
                                 <div className="flex items-center gap-3 text-xs font-bold text-slate-700"><Mail size={16} className="text-blue-600" /> monteimobiliario@gmail.com</div>
                                 <div className="flex items-center gap-3 text-xs font-bold text-slate-700"><Phone size={16} className="text-blue-600" /> +258 87 501 8283</div>
                              </div>
                           </div>
                        </div>
                     </div>
                  </div>
                )}
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Modal Candidatura */}
      {showApplyModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/90 backdrop-blur-xl animate-in fade-in">
