                    <input required disabled={isApplying} value={applyForm.name} onChange={e => setApplyForm({...applyForm, name: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-5 font-bold outline-none border-none focus:ring-4 focus:ring-blue-50 transition-all disabled:opacity-50" placeholder="Nome Completo" />
                    <input required disabled={isApplying} type="email" value={applyForm.email} onChange={e => setApplyForm({...applyForm, email: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-5 font-bold outline-none border-none focus:ring-4 focus:ring-blue-50 transition-all disabled:opacity-50" placeholder="E-mail" />
                    <input required disabled={isApplying} value={applyForm.phone} onChange={e => setApplyForm({...applyForm, phone: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-5 font-bold outline-none border-none focus:ring-4 focus:ring-blue-50 transition-all disabled:opacity-50" placeholder="Telemóvel" />
                    <input disabled={isApplying} value={applyForm.linkedin} onChange={e => setApplyForm({...applyForm, linkedin: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-5 font-bold outline-none border-none focus:ring-4 focus:ring-blue-50 transition-all disabled:opacity-50" placeholder="LinkedIn (Opcional)" />
                  </div>
                  <textarea required disabled={isApplying} value={applyForm.message} onChange={e => setApplyForm({...applyForm, message: e.target.value})} rows={4} className="w-full bg-slate-50 rounded-[2.5rem] p-8 text-xs font-medium outline-none border-none focus:ring-4 focus:ring-blue-50 resize-none shadow-inner transition-all disabled:opacity-50" placeholder="Breve introdução sobre a sua experiência..." />
                  <div className="flex items-start gap-4 p-6 bg-slate-50 rounded-[2rem] border border-slate-100">
                    <input required type="checkbox" checked={hasConsent} onChange={e => setHasConsent(e.target.checked)} className="mt-1 w-5 h-5 rounded text-blue-600 cursor-pointer" />
                    <label className="text-[10px] text-slate-500 font-medium leading-relaxed italic">Autorizo o tratamento dos meus dados para fins de recrutamento pela Monte Imobiliária.</label>
                  </div>
                  <button disabled={isApplying || !hasConsent} type="submit" className="w-full py-7 bg-blue-600 text-white rounded-[2.5rem] font-black text-xs uppercase tracking-widest shadow-2xl hover:bg-slate-900 transition-all flex items-center justify-center gap-3 disabled:opacity-50 active:scale-95">
                    {isApplying ? (
                      <><Loader2 className="animate-spin" /> Enviando Candidatura...</>
                    ) : (
                      <><Send size={18} /> Submeter Candidatura Oficial</>
                    )}
                  </button>
                </form>
              </>
            )}
          </div>
        </div>
      )}

      <style dangerouslySetInnerHTML={{ __html: `
        @keyframes progress-loop {
          0% { transform: translateX(-100%); width: 30%; }
          50% { width: 60%; }
          100% { transform: translateX(333%); width: 30%; }
        }
        .animate-progress-loop {
          animation: progress-loop 2s infinite ease-in-out;
        }
        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          25% { transform: translateX(-4px); }
          75% { transform: translateX(4px); }
        }
        .animate-shake { animation: shake 0.3s ease-in-out; }
      `}} />
    </div>
  );
};

export default CareerView;
